Crear un programa que abre un archivo y cuenta las palabras (separadas por whitespace).


Para trabajar con archivos en modo lectura utilizamos ifstream. Siempre que se trabaje con archivos verificaremos si efectivamente el archivo existe y se pudo abrir correctamente.
Con el operador &gt;&gt; podemos leer el archivo hasta encontrar un espacio en blanco. Con el bucle while repetimos la operación hasta el eof.
Por buenas prácticas, al terminar de utilizar un archivo, lo cerramos con close().


#include &lt;iostream&gt;
#include &lt;fstream&gt;
#include &lt;string&gt;

using namespace std;

int main() {

    string nombreArchivo = "texto.txt"; 

    ifstream archivo(nombreArchivo);

    if (!archivo.is_open()) {
        cerr &lt;&lt; "Error: No se pudo abrir el archivo '" &lt;&lt; nombreArchivo &lt;&lt; "'." &lt;&lt; endl;
        return 1;
    }

    string palabra;
    int contadorPalabras = 0;

    while (archivo &gt;&gt; palabra) {
        contadorPalabras++;
    }

    archivo.close();

    cout &lt;&lt; "El archivo contiene " &lt;&lt; contadorPalabras &lt;&lt; " palabras." &lt;&lt; endl;

    return 0;
}






