Escribir un programa que imprime las líneas de un archivo de texto en orden inverso.


En este caso utilizamos un vector&lt;string&gt; para almacenar todas las líneas del archivo, ya que no podemos leerlo fácilmente al revés. Una vez que tenemos todas las líneas, podemos recorrer el vector desde el final hacia el principio para imprimirlas en orden inverso.
Para extraer la línea completa, incluyendo espacios, utilizamos std::getline() en lugar del operador &gt;&gt;. Y luego para ir agregando cada línea al vector, usamos push_back().
#include &lt;iostream&gt;
#include &lt;fstream&gt;
#include &lt;string&gt;
#include &lt;vector&gt;

using namespace std;

int main() {

    string nombreArchivo = "texto.txt"; 

    ifstream archivo(nombreArchivo);

    if (!archivo.is_open()) {
        cerr &lt;&lt; "Error: No se pudo abrir el archivo '" &lt;&lt; nombreArchivo &lt;&lt; "'." &lt;&lt; endl;
        return 1; 
    }

    vector&lt;string&gt; lineas;
    string lineaActual;

    while (getline(archivo, lineaActual)) {
        lineas.push_back(lineaActual); 
    }

    archivo.close();

    for (int i = lineas.size() - 1; i &gt;= 0; i--) {
        cout &lt;&lt; lineas[i] &lt;&lt; endl;
    }

    return 0;
}






